#include <bits/stdc++.h>
using namespace std;

bool canPartition(vector<int>& nums) {
    int totalSum = 0;
    for(int num : nums) {
        totalSum += num;
    }

    if(totalSum % 2 != 0) return false;

    int target = totalSum / 2;
    int n = nums.size();

    vector<bool> dp(target + 1, false);
    dp[0] = true;

    for(int num : nums) {
        for(int j = target; j >= num; j--) {
            dp[j] = dp[j] || dp[j - num];
        }
    }

    return dp[target];
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> nums(n);
        for(int i = 0; i < n; i++) {
            cin >> nums[i];
        }

        cout << (canPartition(nums) ? "YES" : "NO") << endl;
    }

    return 0;
}
